#include "esc_bldc.h"
#include <ESP32Servo.h>
#define ESC_PIN 13
static Servo esc;
void esc_setup(){esc.attach(ESC_PIN,1000,2000);esc.writeMicroseconds(1000);Serial.println("[esc] OK");}
void esc_arm(){esc.writeMicroseconds(1000);delay(2000);Serial.println("[esc] Armed");}
void esc_set_throttle(int p){int us=map(constrain(p,0,100),0,100,1000,2000);esc.writeMicroseconds(us);}
void esc_stop(){esc.writeMicroseconds(1000);}
